import React, { FC, useEffect } from 'react';
import { PageProps, navigate } from 'gatsby';
import { Helmet } from 'react-helmet';
import { useIntl } from 'gatsby-plugin-intl';

import Layout from '../components/Layout';
import {
  TopSection,
  Navigation,
  Overview,
  Investment,
  Learn,
  Details,
  Instructor,
  Assistant,
  GetInTouch,
} from '../components/AbraCadabra';

import { Anchor } from '../components/AbraCadabra/styles';

const navItems = ['overview', 'investment', 'details', 'instructor'] as const;
export type NavItem = typeof navItems[number];

const AbraCadabra: FC<PageProps> = () => {
  const intl = useIntl();

  useEffect(() => {
    // redirect to en version
    // TODO: make this an HOC?
    if (intl.locale !== 'en') {
      navigate('en/abracadabra');
      return null;
    }
  }, []);


  return (
    <Layout>
      <Helmet>
        <title>AbraCadabra</title>
      </Helmet>
      <TopSection />
      <Navigation />
      <Anchor id="overview" />
      <Overview />
      <Anchor id="investment" />
      <Investment />
      <Learn />
      <Anchor id="details" />
      <Details />
      <Anchor id="instructor" />
      <Instructor />
      <Assistant />
      <GetInTouch />
    </Layout>
  );
};

export default AbraCadabra;
